/// The results of `merge_analysis` indicate the merge opportunities.
enum MergeAnalysis {
  /// No merge is possible.  (Unused.)
  none(0),

  /// A "normal" merge; both HEAD and the given merge input have diverged
  /// from their common ancestor.  The divergent commits must be merged.
  normal(1),

  /// All given merge inputs are reachable from HEAD, meaning the
  /// repository is up-to-date and no merge needs to be performed.
  upToDate(2),

  /// The given merge input is a fast-forward from HEAD and no merge
  /// needs to be performed.  Instead, the client can check out the
  /// given merge input.
  fastforward(4),

  /// The HEAD of the current repository is "unborn" and does not point to
  /// a valid commit.  No merge can be performed, but the caller may wish
  /// to simply set HEAD to the target commit(s).
  unborn(8);

  final int value;
  const MergeAnalysis(this.value);

  static MergeAnalysis fromValue(int value) => switch (value) {
    0 => none,
    1 => normal,
    2 => upToDate,
    4 => fastforward,
    8 => unborn,
    _ => throw ArgumentError('Unknown value for MergeAnalysis: $value'),
  };
}

/// Merge file favor options for `merge_options` instruct the file-level
/// merging functionality how to deal with conflicting regions of the files.
enum MergeFileFavor {
  /// When a region of a file is changed in both branches, a conflict
  /// will be recorded in the index so that `checkout` can produce
  /// a merge file with conflict markers in the working directory.
  /// This is the default.
  normal(0),

  /// When a region of a file is changed in both branches, the file
  /// created in the index will contain the "ours" side of any conflicting
  /// region.  The index will not record a conflict.
  ours(1),

  /// When a region of a file is changed in both branches, the file
  /// created in the index will contain the "theirs" side of any conflicting
  /// region.  The index will not record a conflict.
  theirs(2),

  /// When a region of a file is changed in both branches, the file
  /// created in the index will contain each unique line from each side,
  /// which has the result of combining both files.  The index will not
  /// record a conflict.
  union(3);

  final int value;
  const MergeFileFavor(this.value);

  static MergeFileFavor fromValue(int value) => switch (value) {
    0 => normal,
    1 => ours,
    2 => theirs,
    3 => union,
    _ => throw ArgumentError('Unknown value for MergeFileFavor: $value'),
  };
}

/// File merging flags
enum MergeFileFlag {
