  /// a recursive merge base (by merging the multiple merge bases),
  /// instead simply use the first base.  This flag provides a similar
  /// merge base to `git-merge-resolve`.
  noRecursive(8),

  /// Treat this merge as if it is to produce the virtual base
  /// of a recursive merge.  This will ensure that there are
  /// no conflicts, any conflicting regions will keep conflict
  /// markers in the merge result.
  virtualBase(16);

  final int value;
  const MergeFlag(this.value);

  static MergeFlag fromValue(int value) => switch (value) {
    1 => findRenames,
    2 => failOnConflict,
    4 => skipReuc,
    8 => noRecursive,
    16 => virtualBase,
    _ => throw ArgumentError('Unknown value for MergeFlag: $value'),
  };
}

