///
/// These values represent possible states for the repository to be in,
/// based on the current operation which is ongoing.
enum RepositoryState {
  none(0),
  merge(1),
  revert(2),
  revertSequence(3),
  cherrypick(4),
  cherrypickSequence(5),
  bisect(6),
  rebase(7),
  rebaseInteractive(8),
  rebaseMerge(9),
  applyMailbox(10),
  applyMailboxOrRebase(11);

  final int value;
  const RepositoryState(this.value);

  static RepositoryState fromValue(int value) => switch (value) {
    0 => none,
    1 => merge,
    2 => revert,
    3 => revertSequence,
    4 => cherrypick,
    5 => cherrypickSequence,
    6 => bisect,
    7 => rebase,
    8 => rebaseInteractive,
    9 => rebaseMerge,
    10 => applyMailbox,
    11 => applyMailboxOrRebase,
    _ => throw ArgumentError('Unknown value for RepositoryState: $value'),
  };
}

/// Kinds of reset operation
enum Reset {
  /// < Move the head to the given commit
  soft(1),

  /// < SOFT plus reset index to the commit
  mixed(2),

  /// < MIXED plus changes in working tree discarded
  hard(3);

  final int value;
  const Reset(this.value);

  static Reset fromValue(int value) => switch (value) {
    1 => soft,
    2 => mixed,
    3 => hard,
    _ => throw ArgumentError('Unknown value for Reset: $value'),
  };
}

/// Revparse flags.  These indicate the intended behavior of the spec passed to
/// revparse.
enum RevspecT {
  /// The spec targeted a single object.
  single(1),

  /// The spec targeted a range of commits.
  range(2),

  /// The spec used the '...' operator, which invokes special semantics.
  mergeBase(4);

  final int value;
  const RevspecT(this.value);

  static RevspecT fromValue(int value) => switch (value) {
    1 => single,
    2 => range,
    4 => mergeBase,
    _ => throw ArgumentError('Unknown value for RevspecT: $value'),
  };
}

/// Flags to specify the sorting which a revwalk should perform.
enum Sort {
  /// Sort the output with the same default method from `git`: reverse
  /// chronological order. This is the default sorting for new walkers.
  none(0),

  /// Sort the repository contents in topological order (no parents before
  /// all of its children are shown); this sorting mode can be combined
  /// with time sorting to produce `git`'s `--date-order``.
  topological(1),

  /// Sort the repository contents by commit time;
  /// this sorting mode can be combined with
  /// topological sorting.
  time(2),

  /// Iterate through the repository contents in reverse
  /// order; this sorting mode can be combined with
  /// any of the above.
  reverse(4);

  final int value;
  const Sort(this.value);

  static Sort fromValue(int value) => switch (value) {
    0 => none,
    1 => topological,
    2 => time,
    4 => reverse,
    _ => throw ArgumentError('Unknown value for Sort: $value'),
  };
}

/// Stash application flags.
enum StashApplyFlags {
  default$(0),
  reinstateIndex(1);

  final int value;
  const StashApplyFlags(this.value);

  static StashApplyFlags fromValue(int value) => switch (value) {
    0 => default$,
    1 => reinstateIndex,
    _ => throw ArgumentError('Unknown value for StashApplyFlags: $value'),
  };
}

/// Stash apply progression states
enum StashApplyProgress {
  none(0),

  /// Loading the stashed data from the object database.
  loadingStash(1),

  /// The stored index is being analyzed.
  analyzeIndex(2),

  /// The modified files are being analyzed.
  analyzeModified(3),

  /// The untracked and ignored files are being analyzed.
  analyzeUntracked(4),

  /// The untracked files are being written to disk.
  checkoutUntracked(5),

  /// The modified files are being written to disk.
  checkoutModified(6),

  /// The stash was applied successfully.
  done(7);

  final int value;
  const StashApplyProgress(this.value);

  static StashApplyProgress fromValue(int value) => switch (value) {
    0 => none,
    1 => loadingStash,
    2 => analyzeIndex,
    3 => analyzeModified,
    4 => analyzeUntracked,
    5 => checkoutUntracked,
    6 => checkoutModified,
    7 => done,
    _ => throw ArgumentError('Unknown value for StashApplyProgress: $value'),
  };
}

/// Stash flags
enum StashFlags {
  /// No option, default
  default$(0),

  /// All changes already added to the index are left intact in
  /// the working directory
  keepIndex(1),

  /// All untracked files are also stashed and then cleaned up
  /// from the working directory
  includeUntracked(2),

  /// All ignored files are also stashed and then cleaned up from
  /// the working directory
  includeIgnored(4),

  /// All changes in the index and working directory are left intact
  keepAll(8);

  final int value;
  const StashFlags(this.value);

  static StashFlags fromValue(int value) => switch (value) {
    0 => default$,
    1 => keepIndex,
    2 => includeUntracked,
    4 => includeIgnored,
    8 => keepAll,
    _ => throw ArgumentError('Unknown value for StashFlags: $value'),
  };
}

/// Status flags for a single file.
///
/// A combination of these values will be returned to indicate the status of
/// a file.  Status compares the working directory, the index, and the
/// current HEAD of the repository.  The `GIT_STATUS_INDEX` set of flags
/// represents the status of file in the index relative to the HEAD, and the
/// `GIT_STATUS_WT` set of flags represent the status of the file in the
/// working directory relative to the index.
enum Status {
  current(0),
  indexNew(1),
  indexModified(2),
  indexDeleted(4),
  indexRenamed(8),
  indexTypechange(16),
  wtNew(128),
  wtModified(256),
  wtDeleted(512),
  wtTypechange(1024),
  wtRenamed(2048),
  wtUnreadable(4096),
  ignored(16384),
  conflicted(32768);

  final int value;
  const Status(this.value);

  static Status fromValue(int value) => switch (value) {
    0 => current,
    1 => indexNew,
    2 => indexModified,
    4 => indexDeleted,
    8 => indexRenamed,
    16 => indexTypechange,
    128 => wtNew,
    256 => wtModified,
    512 => wtDeleted,
    1024 => wtTypechange,
    2048 => wtRenamed,
    4096 => wtUnreadable,
    16384 => ignored,
    32768 => conflicted,
    _ => throw ArgumentError('Unknown value for Status: $value'),
  };
}

/// Flags to control status callbacks
///
/// Calling `status_foreach()` is like calling the extended version
/// with: GIT_STATUS_OPT_INCLUDE_IGNORED, GIT_STATUS_OPT_INCLUDE_UNTRACKED,
/// and GIT_STATUS_OPT_RECURSE_UNTRACKED_DIRS.  Those options are bundled
/// together as `GIT_STATUS_OPT_DEFAULTS` if you want them as a baseline.
enum StatusOpt {
  /// Says that callbacks should be made on untracked files.
  /// These will only be made if the workdir files are included in the status
  /// "show" option.
  includeUntracked(1),

  /// Says that ignored files get callbacks.
  /// Again, these callbacks will only be made if the workdir files are
  /// included in the status "show" option.
  includeIgnored(2),

  /// Indicates that callback should be made even on unmodified files.
  includeUnmodified(4),

  /// Indicates that submodules should be skipped.
  /// This only applies if there are no pending typechanges to the submodule
  /// (either from or to another type).
  excludeSubmodules(8),

  /// Indicates that all files in untracked directories should be included.
  /// Normally if an entire directory is new, then just the top-level
  /// directory is included (with a trailing slash on the entry name).
  /// This flag says to include all of the individual files in the directory
  /// instead.
  recurseUntrackedDirs(16),

  /// Indicates that the given path should be treated as a literal path,
  /// and not as a pathspec pattern.
  disablePathspecMatch(32),

  /// Indicates that the contents of ignored directories should be included
  /// in the status. This is like doing `git ls-files -o -i --exclude-standard`
  /// with core git.
  recurseIgnoredDirs(64),

  /// Indicates that rename detection should be processed between the head and
  /// the index and enables the GIT_STATUS_INDEX_RENAMED as a possible status
  /// flag.
  renamesHeadToIndex(128),

  /// Indicates that rename detection should be run between the index and the
  /// working directory and enabled GIT_STATUS_WT_RENAMED as a possible status
  /// flag.
  renamesIndexToWorkdir(256),

  /// Overrides the native case sensitivity for the file system and forces
  /// the output to be in case-sensitive order.
  sortCaseSensitively(512),

  /// Overrides the native case sensitivity for the file system and forces
  /// the output to be in case-insensitive order.
  sortCaseInsensitively(1024),

  /// Iindicates that rename detection should include rewritten files.
  renamesFromRewrites(2048),

  /// Bypasses the default status behavior of doing a "soft" index reload
  /// (i.e. reloading the index data if the file on disk has been modified
  /// outside libgit2).
  noRefresh(4096),

  /// Tells libgit2 to refresh the stat cache in the index for files that are
  /// unchanged but have out of date stat einformation in the index.
  /// It will result in less work being done on subsequent calls to get status.
  /// This is mutually exclusive with the NO_REFRESH option.
  updateIndex(8192),

  /// Normally files that cannot be opened or read are ignored as
  /// these are often transient files; this option will return
  /// unreadable files as `GIT_STATUS_WT_UNREADABLE`.
  includeUnreadable(16384),

  /// Unreadable files will be detected and given the status
  /// untracked instead of unreadable.
  includeUnreadableAsUntracked(32768);

  final int value;
  const StatusOpt(this.value);

  static StatusOpt fromValue(int value) => switch (value) {
    1 => includeUntracked,
    2 => includeIgnored,
    4 => includeUnmodified,
    8 => excludeSubmodules,
    16 => recurseUntrackedDirs,
    32 => disablePathspecMatch,
    64 => recurseIgnoredDirs,
    128 => renamesHeadToIndex,
    256 => renamesIndexToWorkdir,
    512 => sortCaseSensitively,
    1024 => sortCaseInsensitively,
    2048 => renamesFromRewrites,
    4096 => noRefresh,
    8192 => updateIndex,
    16384 => includeUnreadable,
    32768 => includeUnreadableAsUntracked,
    _ => throw ArgumentError('Unknown value for StatusOpt: $value'),
  };
}

/// Select the files on which to report status.
///
/// With `status_foreach_ext`, this will control which changes get
/// callbacks.  With `status_list_new`, these will control which
/// changes are included in the list.
enum StatusShow {
  /// The default. This roughly matches `git status --porcelain` regarding
  /// which files are included and in what order.
  indexAndWorkdir(0),

  /// Only gives status based on HEAD to index comparison, not looking at
  /// working directory changes.
  indexOnly(1),

  /// Only gives status based on index to working directory comparison,
  /// not comparing the index to the HEAD.
  workdirOnly(2);

  final int value;
  const StatusShow(this.value);

  static StatusShow fromValue(int value) => switch (value) {
    0 => indexAndWorkdir,
    1 => indexOnly,
    2 => workdirOnly,
    _ => throw ArgumentError('Unknown value for StatusShow: $value'),
  };
}

/// Submodule ignore values
///
/// These values represent settings for the `submodule.$name.ignore`
/// configuration value which says how deeply to look at the working
/// directory when getting submodule status.
///
/// You can override this value in memory on a per-submodule basis with
/// `submodule_set_ignore()` and can write the changed value to disk
/// with `submodule_save()`.  If you have overwritten the value, you
/// can revert to the on disk value by using `GIT_SUBMODULE_IGNORE_RESET`.
///
/// The values are:
///
/// - GIT_SUBMODULE_IGNORE_UNSPECIFIED: use the submodule's configuration
/// - GIT_SUBMODULE_IGNORE_NONE: don't ignore any change - i.e. even an
/// untracked file, will mark the submodule as dirty.  Ignored files are
/// still ignored, of course.
/// - GIT_SUBMODULE_IGNORE_UNTRACKED: ignore untracked files; only changes
/// to tracked files, or the index or the HEAD commit will matter.
/// - GIT_SUBMODULE_IGNORE_DIRTY: ignore changes in the working directory,
/// only considering changes if the HEAD of submodule has moved from the
/// value in the superproject.
/// - GIT_SUBMODULE_IGNORE_ALL: never check if the submodule is dirty
/// - GIT_SUBMODULE_IGNORE_DEFAULT: not used except as static initializer
/// when we don't want any particular ignore rule to be specified.
enum SubmoduleIgnore {
  /// < use the submodule's configuration
  unspecified(-1),

  /// < any change or untracked == dirty
  none(1),

  /// < dirty if tracked files change
  untracked(2),

  /// < only dirty if HEAD moved
  dirty(3),

  /// < never dirty
  all(4);

  final int value;
  const SubmoduleIgnore(this.value);

  static SubmoduleIgnore fromValue(int value) => switch (value) {
    -1 => unspecified,
    1 => none,
    2 => untracked,
    3 => dirty,
    4 => all,
    _ => throw ArgumentError('Unknown value for SubmoduleIgnore: $value'),
  };
}

/// Options for submodule recurse.
///
/// Represent the value of `submodule.$name.fetchRecurseSubmodules`
///
/// * GIT_SUBMODULE_RECURSE_NO    - do no recurse into submodules
/// * GIT_SUBMODULE_RECURSE_YES   - recurse into submodules
/// * GIT_SUBMODULE_RECURSE_ONDEMAND - recurse into submodules only when
/// commit not already in local clone
enum SubmoduleRecurse {
  no(0),
  yes(1),
  ondemand(2);

  final int value;
  const SubmoduleRecurse(this.value);

  static SubmoduleRecurse fromValue(int value) => switch (value) {
    0 => no,
    1 => yes,
    2 => ondemand,
    _ => throw ArgumentError('Unknown value for SubmoduleRecurse: $value'),
  };
}

/// Return codes for submodule status.
///
/// A combination of these flags will be returned to describe the status of a
/// submodule.  Depending on the "ignore" property of the submodule, some of
/// the flags may never be returned because they indicate changes that are
/// supposed to be ignored.
///
/// Submodule info is contained in 4 places: the HEAD tree, the index, config
/// files (both .git/config and .gitmodules), and the working directory.  Any
/// or all of those places might be missing information about the submodule
/// depending on what state the repo is in.  We consider all four places to
/// build the combination of status flags.
///
/// There are four values that are not really status, but give basic info
/// about what sources of submodule data are available.  These will be
/// returned even if ignore is set to "ALL".
///
/// * IN_HEAD   - superproject head contains submodule
/// * IN_INDEX  - superproject index contains submodule
/// * IN_CONFIG - superproject gitmodules has submodule
/// * IN_WD     - superproject workdir has submodule
///
/// The following values will be returned so long as ignore is not "ALL".
///
/// * INDEX_ADDED       - in index, not in head
/// * INDEX_DELETED     - in head, not in index
/// * INDEX_MODIFIED    - index and head don't match
/// * WD_UNINITIALIZED  - workdir contains empty directory
/// * WD_ADDED          - in workdir, not index
/// * WD_DELETED        - in index, not workdir
/// * WD_MODIFIED       - index and workdir head don't match
///
/// The following can only be returned if ignore is "NONE" or "UNTRACKED".
///
/// * WD_INDEX_MODIFIED - submodule workdir index is dirty
/// * WD_WD_MODIFIED    - submodule workdir has modified files
///
/// Lastly, the following will only be returned for ignore "NONE".
///
/// * WD_UNTRACKED      - wd contains untracked files
enum SubmoduleStatus {
  inHead(1),
  inIndex(2),
  inConfig(4),
  inWd(8),
  indexAdded(16),
  indexDeleted(32),
  indexModified(64),
  wdUninitialized(128),
  wdAdded(256),
  wdDeleted(512),
  wdModified(1024),
  wdIndexModified(2048),
  wdWdModified(4096),
  wdUntracked(8192);

  final int value;
  const SubmoduleStatus(this.value);

  static SubmoduleStatus fromValue(int value) => switch (value) {
    1 => inHead,
    2 => inIndex,
    4 => inConfig,
    8 => inWd,
    16 => indexAdded,
    32 => indexDeleted,
    64 => indexModified,
    128 => wdUninitialized,
    256 => wdAdded,
    512 => wdDeleted,
    1024 => wdModified,
    2048 => wdIndexModified,
    4096 => wdWdModified,
    8192 => wdUntracked,
    _ => throw ArgumentError('Unknown value for SubmoduleStatus: $value'),
  };
}

/// Submodule update values
///
/// These values represent settings for the `submodule.$name.update`
/// configuration value which says how to handle `git submodule update` for
/// this submodule.  The value is usually set in the ".gitmodules" file and
/// copied to ".git/config" when the submodule is initialized.
///
/// You can override this setting on a per-submodule basis with
/// `submodule_set_update()` and write the changed value to disk using
/// `submodule_save()`.  If you have overwritten the value, you can
/// revert it by passing `GIT_SUBMODULE_UPDATE_RESET` to the set function.
///
/// The values are:
///
/// - GIT_SUBMODULE_UPDATE_CHECKOUT: the default; when a submodule is
/// updated, checkout the new detached HEAD to the submodule directory.
/// - GIT_SUBMODULE_UPDATE_REBASE: update by rebasing the current checked
/// out branch onto the commit from the superproject.
/// - GIT_SUBMODULE_UPDATE_MERGE: update by merging the commit in the
/// superproject into the current checkout out branch of the submodule.
/// - GIT_SUBMODULE_UPDATE_NONE: do not update this submodule even when
/// the commit in the superproject is updated.
/// - GIT_SUBMODULE_UPDATE_DEFAULT: not used except as static initializer
/// when we don't want any particular update rule to be specified.
enum SubmoduleUpdate {
  checkout(1),
  rebase(2),
  merge(3),
  none(4),
  default$(0);

  final int value;
  const SubmoduleUpdate(this.value);

  static SubmoduleUpdate fromValue(int value) => switch (value) {
    1 => checkout,
    2 => rebase,
    3 => merge,
    4 => none,
    0 => default$,
    _ => throw ArgumentError('Unknown value for SubmoduleUpdate: $value'),
  };
}

/// Available tracing levels.  When tracing is set to a particular level,
/// callers will be provided tracing at the given level and all lower levels.
enum TraceLevel {
  /// No tracing will be performed.
  none(0),

  /// Severe errors that may impact the program's execution
  fatal(1),

  /// Errors that do not impact the program's execution
  error(2),

  /// Warnings that suggest abnormal data
  warn(3),

  /// Informational messages about program execution
  info(4),

  /// Detailed data that allows for debugging
  debug(5),

  /// Exceptionally detailed debugging data
  trace(6);

  final int value;
  const TraceLevel(this.value);

  static TraceLevel fromValue(int value) => switch (value) {
    0 => none,
    1 => fatal,
    2 => error,
    3 => warn,
    4 => info,
    5 => debug,
    6 => trace,
    _ => throw ArgumentError('Unknown value for TraceLevel: $value'),
  };
}

/// The kind of update to perform
enum TreeUpdateT {
  /// Update or insert an entry at the specified path
  upsert(0),

  /// Remove an entry from the specified path
  remove(1);

  final int value;
  const TreeUpdateT(this.value);

  static TreeUpdateT fromValue(int value) => switch (value) {
    0 => upsert,
    1 => remove,
    _ => throw ArgumentError('Unknown value for TreeUpdateT: $value'),
  };
}

/// Tree traversal modes
enum TreewalkMode {
  pre(0),
  post(1);

  final int value;
  const TreewalkMode(this.value);

  static TreewalkMode fromValue(int value) => switch (value) {
    0 => pre,
    1 => post,
    _ => throw ArgumentError('Unknown value for TreewalkMode: $value'),
  };
}

/// Flags which can be passed to worktree_prune to alter its
/// behavior.
enum WorktreePrune {
  valid(1),
  locked(2),
  workingTree(4);

  final int value;
  const WorktreePrune(this.value);

  static WorktreePrune fromValue(int value) => switch (value) {
    1 => valid,
    2 => locked,
    4 => workingTree,
    _ => throw ArgumentError('Unknown value for WorktreePrune: $value'),
  };
}
